{
    "name": "Welcome Flow",
    "trigger": "hi",
    "nodes": [
        {
            "id": "1",
            "type": "text",
            "data": { "text": "Hello 👋 Welcome to our service!" },
            "next": "2"
        },
        {
            "id": "2",
            "type": "buttons",
            "data": {
                "text": "How can I help you today?",
                "buttons": [
                    { "id": "order", "title": "📦 Order" },
                    { "id": "support", "title": "🛠 Support" }
                ]
            }
        },
        {
            "id": "order",
            "type": "text",
            "data": { "text": "Great! Opening the order catalog..." }
        },
        {
            "id": "support",
            "type": "text",
            "data": { "text": "Connecting you to a support agent. Please wait..." }
        }
    ]
}

{
    "name": "Condition Flow",
    "trigger": "test",
    "nodes": [
        {
            "id": "1",
            "type": "buttons",
            "data": {
                "text": "Are you a member?",
                "buttons": [
                    { "id": "yes", "title": "Yes" },
                    { "id": "no", "title": "No" }
                ]
            },
            "next": "cond_1"
        },
        {
            "id": "cond_1",
            "type": "condition",
            "data": {
                "key": "1",
                "operator": "==",
                "value": "yes",
                "onTrue": "member_msg",
                "onFalse": "guest_msg"
            }
        },
        {
            "id": "member_msg",
            "type": "text",
            "data": { "text": "Welcome back, Member! 🌟" }
        },
        {
            "id": "guest_msg",
            "type": "text",
            "data": { "text": "Hello Guest! Please sign up to continue." }
        }
    ]
}
